import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

/**
 * Tests for the WrappingRule related to string templates.
 *
 * See: https://github.com/pinterest/ktlint/issues/1776
 */
internal class WrappingRuleStringTemplateTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Issue 1776 - Given a raw string with a let block inside then do not report false positive`() {
        val code =
            """
            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated_and_generates_an_error
                        WHERE 1 = 1
                        ${"$"}{query.gameId?.let { "AND id = ?" } ?: ""}    
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a raw string with a lambda block inside should not be wrapped`() {
        val code =
            """
            val s = $MULTILINE_STRING_QUOTE
                Some text with very long content that should exceed the max line length limit when checked by the rule
                ${"$"}{items.filter { it.isNotEmpty() }.joinToString()}
            $MULTILINE_STRING_QUOTE
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a raw string with multiple lambda blocks should not be wrapped`() {
        val code =
            """
            val sql = $MULTILINE_STRING_QUOTE
                SELECT * FROM users
                WHERE 1 = 1
                ${"$"}{name?.let { "AND name = ?" } ?: ""}
                ${"$"}{age?.let { "AND age > ?" } ?: ""}
                ${"$"}{country?.let { "AND country = ?" } ?: ""}
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a raw string with nested lambda in string template should not be wrapped`() {
        val code =
            """
            fun buildQuery(): String {
                val condition = $MULTILINE_STRING_QUOTE
                    ${"$"}{values.mapNotNull { v -> v.takeIf { it > 0 }?.let { "value = ${"$"}it" } }.joinToString(" OR ")}
                $MULTILINE_STRING_QUOTE.trimIndent()
                return condition
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a non-raw string with let block in short line should not be wrapped`() {
        val code =
            """
            val s = "${"$"}{foo?.let { bar }}"
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline block outside of string template should still be wrapped`() {
        val code =
            """
            fun test() {
                foo.let { bar
                    baz }
            }
            """.trimIndent()
        val formattedCode =
            """
            fun test() {
                foo.let {
                    bar
                    baz
                }
            }
            """.trimIndent()
        wrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolations(
                com.pinterest.ktlint.test.LintViolation(2, 14, "Missing newline after \"{\""),
                com.pinterest.ktlint.test.LintViolation(3, 12, "Missing newline before \"}\""),
            ).isFormattedAs(formattedCode)
    }
}
